// Projection used to generate the paths above. Use this to place point
// features (city markers, etc.) in the same SVG coordinate space.
const COS_MID_LAT = 0.9276951476;
const PMIN_X = 63.176552;
const PMIN_Y = -37.076958;
const SCALE = 35.631117;
const OX = 15.961748;
const OY = 10.0;

export function projectLngLat(lng: number, lat: number): { x: number; y: number } {
  const x = (lng * COS_MID_LAT - PMIN_X) * SCALE + OX;
  const y = (-lat - PMIN_Y) * SCALE + OY;
  return { x, y };
}
